INSERT INTO `book` VALUES (1,3,'金融思维','https://mediaminds.oss-cn-beijing.aliyuncs.com/bookPic/a51ea165-130e-4d63-baaf-5c780343e121.png','李成才推荐！《华尔街》《货币》学术顾问与总撰稿，以纪录片的务实加上金融事例的不可思议，教你掌握金融常识、培养金融思维，熟练投资理财',0,'2023-02-03 14:50:49','2023-04-07 13:52:52',NULL),(2,2,'三体','https://mediaminds.oss-cn-beijing.aliyuncs.com/bookPic/65e4415b-a990-4289-be1c-f8927362358b.png','《三体》第73届世界科幻雨果奖获奖作品，银河奖特别奖，《三体3》轨迹奖长篇科幻小说！2017年世界雨果奖提名作品。',0,'2023-02-04 12:37:44','2023-04-07 15:14:03',NULL),(3,3,'财富自由的起点','https://mediaminds.oss-cn-beijing.aliyuncs.com/bookPic/b84c01c3-cb55-49e1-8d50-be472daa357d.png','财富自由的起点 内卷时代更适合年轻人的投资创富指南，揭示新时代财富运行的底层逻辑，助你轻松开启财富自由之门。购书还可获取“钱月九财富私享课”等惊喜福利',0,'2023-02-04 12:42:12','2023-04-07 13:51:58',NULL),(4,2,'献给阿尔吉侬的花束','https://mediaminds.oss-cn-beijing.aliyuncs.com/bookPic/13eee556-936b-4e8c-a14a-bf68728502c9.png','豆瓣9.1高分，豆瓣科幻小说榜Top10，6万+评分，10万+想读 囊括世界科幻小说两项大奖“星云奖”“雨果奖”，感动无数读者的人性关怀杰作 30多种语言译本，全球销量超过600万册',0,'2023-03-04 10:47:02','2023-04-07 11:28:04',NULL),(5,2,'球状闪电','https://mediaminds.oss-cn-beijing.aliyuncs.com/bookPic/4d274017-3c3f-4f07-a1d9-8f5f0f40b148.png','《三体》系列前传， 亚洲首位雨果奖得主 第十八届银河奖特别奖 十届银河奖得主，刘慈欣被授予2018年度克拉克想象力服务社会奖',0,'2023-03-04 10:56:39','2023-04-07 11:27:03',NULL),(6,2,'超新星纪元','https://mediaminds.oss-cn-beijing.aliyuncs.com/bookPic/b06c3ad1-b6ce-44a7-8bde-d4d440ca5ba1.png','世界没有大人了。如此简单的想法，推演出乍看荒诞细想真实令人发冷的未来。我们以为人类的传承理所当然，但完全由孩子创造的世界，还会和过去一样吗？',0,'2023-03-04 10:57:02','2023-04-07 11:36:42',NULL),(7,2,'带上她的眼睛','https://mediaminds.oss-cn-beijing.aliyuncs.com/bookPic/9a3fdcf4-4c36-46bb-bae2-fbb772ae106f.png','科幻电影《流浪地球》《疯狂的外星人》原著小说 入选7年级下语文教材',0,'2023-03-04 11:09:14','2023-04-07 11:36:34',NULL),(8,2,'银河帝国：基地','https://mediaminds.oss-cn-beijing.aliyuncs.com/bookPic/e9dc4ce6-c977-4584-be8a-61cd17fc03e6.png','阿西莫夫：永恒的科幻经典！阿西莫夫封神之作。人类历史上不容错过的系列小说——世界SF小说协会，1966年，俄亥俄州。附赠“银河帝国行政区”海报。读客熊猫君出品',0,'2023-03-04 13:55:54','2023-04-07 11:36:53',NULL),(9,3,'富爸爸穷爸爸','https://mediaminds.oss-cn-beijing.aliyuncs.com/bookPic/0e171ec7-1f04-462f-ae83-aae1244eacdd.png','关于财商教育、投资理财知识的经典之作，你问十个人关于财商和理财的书籍，九个人会给你《推荐富爸爸穷爸爸》。里面有很多让你脑洞大开、重新审视三观的东西让你去发现。',0,'2023-03-04 13:56:19','2023-04-07 13:51:09',NULL),(10,3,'手把手教你读财报','https://mediaminds.oss-cn-beijing.aliyuncs.com/bookPic/9f0adada-92f6-4fcf-aff6-18b24c083384.png','知名投资人，畅销书作家唐朝力作！投资者写给投资者的排雷秘籍，自学者写给自学者的财报入门',0,'2023-03-04 13:56:36','2023-04-07 13:49:59',NULL),(11,2,'克莱因壶','https://mediaminds.oss-cn-beijing.aliyuncs.com/bookPic/0cc057ff-207b-40d8-950c-2c1ba834847c.jpg','入围豆瓣图书Top130，豆瓣热门日系推理图书NO.6！日本虚拟现实VR题材开山神作！什么时候，你开始怀疑这个世界是假的？',0,'2023-03-04 13:57:11','2023-04-07 11:17:22',NULL),(23,3,'日本蜡烛图技术','https://mediaminds.oss-cn-beijing.aliyuncs.com/bookPic/62076b67-e374-4631-a6af-6d1d1bd85c10.png','全新修订超20万字！“K线之父”史蒂夫·尼森畅销近30年的金融投资经典，中国知名金融学者和从业者丁圣元译，让大众熟知蜡烛图技术的开山之作。附赠作者印签+特写寄语。',0,'2023-04-07 14:33:43','2023-04-07 14:33:43',NULL),(24,3,'财务自由之路','https://mediaminds.oss-cn-beijing.aliyuncs.com/bookPic/ae9cf546-d203-4775-a17c-01a2d08e8021.png','★全球销量1000万册 ★欧洲*金钱教练，轰动全球财经界的“欧洲巴菲特”博多·舍费尔 ★25万学员亲赴欧洲听他演讲，获得财务自由！ ★理念指导+操作技巧 助力投资新手、投资高手！',0,'2023-04-07 14:35:05','2023-04-07 14:35:05',NULL),(25,3,'聪明的投资者','https://mediaminds.oss-cn-beijing.aliyuncs.com/bookPic/84849ecb-9815-4e4b-9ef1-0890001ac588.png','主要面向个人投资者，全面体现了格雷厄姆的价值投资思想，为普通人在证券投资策略的选择和执行方面提供了重要的指导。',0,'2023-04-07 14:37:09','2023-04-07 14:37:09',NULL),(26,3,'股市进阶之道','https://mediaminds.oss-cn-beijing.aliyuncs.com/bookPic/15f4c0ff-bc29-40b8-9c95-6c2022945f1c.png','雪球、新浪人气博主水晶苍蝇拍鼎力之作,球创始人方三文、i美股资产管理人梁剑倾力推荐；徐星投资管理有限公司总经理 张东伟作序，腾讯财经专题推荐.',0,'2023-04-07 14:38:12','2023-04-07 14:38:12',NULL),(27,6,'半小时漫画中国地理','https://mediaminds.oss-cn-beijing.aliyuncs.com/bookPic/42d5f2ab-5904-4989-b26a-ed8a9b94fbbe.png','假如全中国是个班级，地理知识就很好记。 漫画式科普开创者、3500万粉丝的陈磊 半小时漫画团队科普地理新系列！ 如果我们能把全中国看成一个班级，那这事儿就好理解了。 四川是外柔内刚的同学：平时看起来懒懒的很好',0,'2023-04-07 14:39:46','2023-04-07 14:39:46',NULL),(28,6,'大横断','https://mediaminds.oss-cn-beijing.aliyuncs.com/bookPic/d206cc44-531e-4fe4-84e7-61460818dbb4.png','本书历时8 年，集百位户外人、摄影师及撰稿人对横断山区的挚爱与热忱，在峡谷密林、雪山冰川，风餐露宿，坚持前期文图实采；并以图文结合的方式，首次翔实而严谨地梳理了横断七脉，更加清晰直观地展现出横断山区的地形',0,'2023-04-07 14:41:21','2023-04-07 14:41:21',NULL),(29,6,'上帝掷骰子么','https://mediaminds.oss-cn-beijing.aliyuncs.com/bookPic/90b26ee5-b572-4241-93c5-aba2af490ca1.png','国内ZUI畅销的科普神作，豆瓣评分9.2，创科普类图书中强大口碑。 刘慈欣盛赞： 教科书要是能这么有趣就好了！ 百万读者惊呼：原来物理这么燃！ 2.扎克伯格关注的科技前沿，全球下一轮新科技革命的引爆点。 美国能源部',0,'2023-04-07 14:42:36','2023-04-07 14:42:36',NULL),(30,4,'伟人传记典藏纪念版','https://mediaminds.oss-cn-beijing.aliyuncs.com/bookPic/8a9def36-9deb-43c9-b880-283c88341d7e.png','方学者笔下的开国领袖传记。不懂得*、周恩来、邓小平，就不会真正理解一百年来的中国历史。',0,'2023-04-07 14:52:54','2024-01-04 12:41:14',NULL),(31,4,'赢家：齐达内传','https://mediaminds.oss-cn-beijing.aliyuncs.com/bookPic/f9e1a95f-0251-44f5-8b19-91f4ca9b2904.png','追踪报道30余年，著成的齐达内权威传记。读《齐达内传》，参透赢家哲学。书中全景纪录了齐达内传奇的足球生涯，帮你领悟“玄学”大师成功背后的人生哲学。',0,'2023-04-07 14:54:22','2023-04-07 14:54:22',NULL),(32,4,'库有引力：斯蒂芬·库里传','https://mediaminds.oss-cn-beijing.aliyuncs.com/bookPic/acc74d1a-4cc3-4ba6-9d65-f3274e3965d0.png','至高规格致敬珍藏，海量图文甄选打造。 豪华附赠：库里珍藏大扑克牌 +《狂飙盛宴》超神纪念大海报+库里荣耀内藏长卷',0,'2023-04-07 14:56:37','2024-01-04 12:52:52',NULL),(33,4,'伊布自传','https://mediaminds.oss-cn-beijing.aliyuncs.com/bookPic/3e3a0e14-1395-40de-90a7-8ab5312dba87.png','“来时我如国王，去时我如传奇！这本书讲述的是我一路走过的足球旅程。别辜负自己的天赋，相信自己，努力工作。我的亲身经历已经证明，如果你永不言弃，一切皆有可能。”《天下足球》翻译作品。',0,'2023-04-07 14:57:49','2024-01-04 12:41:14',NULL),(34,4,'随风不逝·张国荣','https://mediaminds.oss-cn-beijing.aliyuncs.com/bookPic/4c7a5fa4-290f-410d-bbca-e07f6d2cec93.png','20周年，是时候想遍，心中所爱名字——张国荣',0,'2023-04-07 14:58:53','2024-01-04 12:39:13',NULL),(35,4,'拉下百叶窗的午后','https://mediaminds.oss-cn-beijing.aliyuncs.com/bookPic/95e4af95-7283-43d9-b2e2-e17852ce2fc5.png','入选某瓣2021年度艺术·设计榜单，英伦传奇乐队Suede山羊皮主唱布雷特·安德森回忆录 揭秘山羊皮从一夜成名到黯然解散全过程 深度剖析音乐产业生态|揭示音乐产业运转真相|音乐爱好者的诚意之作',0,'2023-04-07 15:07:55','2024-01-04 12:41:14',NULL),(36,4,'苏东坡传','https://mediaminds.oss-cn-beijing.aliyuncs.com/bookPic/5b7f9bd2-30d0-4414-be66-931d937ce808.png','隐世才女白落梅慢沏一碗清茶，为你细述一代文豪苏东坡的快意人生。逆旅而行，几多困顿；飘然如风，几多潇洒。唯美插图珍藏版，附赠手绘精美书签！',0,'2023-04-07 15:08:52','2024-01-04 12:38:38',NULL),(37,1,'习近平新时代中国特色社会主义思想概论 2023新版','https://mediaminds.oss-cn-beijing.aliyuncs.com/bookPic/91ff6737-951d-4c76-80a0-63fa0d01e9c5.png','该书是中央马工程重点教材，由马克思主义理论研究和建设工程办公室统筹组织编写，是第一部全面系统体现习近平新时代中国特色社会主义思想的全国高校思政课统编教材，由导论、结语和17章正文组成，各章均设有学习要点、本章小结、思考题及总书记金句、知识拓展、图表等多种形式的辅文。',0,'2023-04-07 15:51:35','2024-01-04 12:40:48',NULL),(38,1,'中医基础理论(五版教材)','https://mediaminds.oss-cn-beijing.aliyuncs.com/bookPic/1ad76c51-5409-496e-942d-a7e51bf3a48a.png','中医基础理论，是研究和阐释中医学的基础理论和基本知识的一门学科。它的内容包括阴阳五行、藏象、经络、气血津液、病因和病机等方面的基础理论和基本知识，是学习中医中药其他各门学科的基础，是学习和研究中医药学的一门必修的基础理论课程。',0,'2023-04-07 15:52:22','2024-01-04 12:35:29',NULL),(39,1,'刑法学（第六版 上下册）\r\n','https://mediaminds.oss-cn-beijing.aliyuncs.com/bookPic/5dd2a600-2790-46bd-80db-dbed280027b3.png','张明楷教授代表作 扩容近六十万字，增加刑十一、刑十相关内容，增删、修改刑法基础论、犯罪论、法律后果论、罪刑各论等内容',0,'2023-04-07 15:53:21','2023-04-07 15:53:21',NULL),(40,1,'普通心理学(第5版）','https://mediaminds.oss-cn-beijing.aliyuncs.com/bookPic/8608474f-eb9c-46d1-b6cb-ce6fda983d07.png','它既是心理学专业的基础课教材，也是相关专业和心理学爱好者的入门教材，还是部分高校招收心理学博、硕士研究生的重要参考教材',0,'2023-04-07 15:54:29','2024-01-04 12:40:48',NULL),(41,8,'有一年','https://mediaminds.oss-cn-beijing.aliyuncs.com/bookPic/a8849063-d1f6-453a-b99b-749c7a39bac0.png','知名插画师、畅销漫画作品《生活蒙太奇》作者天然的插画作品集。这是一个生活观察者对美好生活无时无刻的记录。同时也是一个关于美的创作试验：连续365天生活速写，700多幅作品合集，呈现如诗如画的有一年。',0,'2023-04-07 15:56:02','2023-05-12 16:55:07',NULL),(42,8,'艺术与文明','https://mediaminds.oss-cn-beijing.aliyuncs.com/bookPic/c6b7ce8e-01a2-4dae-997b-93d1061f2a44.png','著名美术史家范景中五十年心力之作，聚焦文艺复兴到18世纪天才艺术家层出不穷的黄金时代。陈丹青、许知远、巫鸿、朱良志、吕澎联合推荐，献给所有热爱艺术、热爱美的你。当当专属双赠品，送完为止！',0,'2023-04-07 15:57:00','2024-01-04 12:09:19',NULL),(43,8,'入世的巅峰','https://mediaminds.oss-cn-beijing.aliyuncs.com/bookPic/9506aff1-3cf4-47f3-b114-77501eb856af.png','清明上河图，藏着中国人的精神！百万人气公号“近似于透明的深蓝”作品，讲述流淌在我们骨血里的思想、文化与美的力量，更关于人如何过好这一生。豆瓣高分佳作！悲悯，绚丽又静默如迷。蒋勋、Tango推荐',0,'2023-04-07 15:57:46','2024-01-04 12:09:19',NULL),(44,8,'解异集','https://mediaminds.oss-cn-beijing.aliyuncs.com/bookPic/3ca39e37-1a8e-4df4-b620-a78e67f19fec.png','人气画手仙女绝美原创百妖神怪图鉴，出自近百部中国志怪典籍和民间传说，如《聊斋》中的鬼魅、《子不语》中的妖魔、《山海经》中的神祇等，为你打开浩瀚的民族传统文化宝库。',0,'2023-04-07 15:58:43','2023-05-14 10:32:39',NULL),(46,4,'平步青云','https://mediaminds.oss-cn-beijing.aliyuncs.com/book/89481e0a-af07-45f7-8e00-4100fa8ddff5.jpg','柳浩天转业到千湖镇上任的第一天就直接被架空了，面对着与镇长梁友德之间不可调和的观念冲突，面对阴险奸诈的天星公司以及天星公司所组织起来的庞大人脉关系网络，柳浩天绝不妥协，铁腕整顿，围绕着如何保障民生发展经济，一场场激烈的斗争由此拉开序幕……\n尘埃落定之时，结果出炉，柳浩天彻底愤怒了……\n官之大者，为国为民。',679,'2025-05-07 00:54:38','2025-05-11 11:31:19','梦入洪荒'),(47,2,'开端','https://mediaminds.oss-cn-beijing.aliyuncs.com/book/8beb9f3e-44a3-40fb-b1b6-c1336a9aa99c.jpg','李诗情坐上了一辆公交车，原以为会与往常一般到达目的地，却没想到踏上了一段无限循环的“死亡之旅”……\n如果再这么“出事”下去，她难保不会疯。\n但被她意外拉入“循环”的肖鹤云却说：“像我们这样连死几十次都没有放弃希望的人，还有什么事是做不到的呢？毕竟……没有什么事比从容赴死更难的了啊。”',42,'2025-05-07 00:54:39','2025-05-11 11:32:22','祈祷君');
