DROP TABLE IF EXISTS `book_chapter`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `book_chapter` (
                                `id` int NOT NULL AUTO_INCREMENT COMMENT '主键ID',
                                `book_id` int NOT NULL COMMENT '关联书籍ID（外键，指向book_product.id）',
                                `chapter_number` int DEFAULT NULL COMMENT '章节序号（可选，便于排序）',
                                `chapter_title` varchar(255) NOT NULL COMMENT '章节名',
                                `content_path` varchar(255) NOT NULL COMMENT '正文TXT文件路径',
                                `word_count` int DEFAULT NULL COMMENT '正文字数',
                                `create_time` datetime DEFAULT NULL COMMENT '创建时间',
                                `update_time` datetime DEFAULT NULL COMMENT '修改时间',
                                PRIMARY KEY (`id`) USING BTREE,
                                KEY `book_id` (`book_id`)
) ENGINE=InnoDB AUTO_INCREMENT=722 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci ROW_FORMAT=DYNAMIC COMMENT='书籍章节信息';
/*!40101 SET character_set_client = @saved_cs_client */;

