DROP TABLE IF EXISTS `book_favorite`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `book_favorite` (
                                 `id` int NOT NULL AUTO_INCREMENT COMMENT '主键ID',
                                 `user_id` varchar(20) NOT NULL COMMENT '用户ID',
                                 `book_id` int NOT NULL COMMENT '关联书籍ID（外键，指向book_product.id）',
                                 `chapter_id` int DEFAULT NULL COMMENT '关联章节ID（外键，指向book_chapter.id，可为空）',
                                 `create_time` datetime DEFAULT NULL COMMENT '收藏时间',
                                 PRIMARY KEY (`id`) USING BTREE,
                                 UNIQUE KEY `unique_favorite` (`user_id`,`book_id`,`chapter_id`) COMMENT '防止重复收藏',
                                 KEY `book_id` (`book_id`),
                                 KEY `chapter_id` (`chapter_id`)
) ENGINE=InnoDB AUTO_INCREMENT=32 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci ROW_FORMAT=DYNAMIC COMMENT='用户收藏';
